#include <stdio.h>

int main(void) {	int a, b, opcion;	printf("Ingrese dos numeros enteros: ");	if (scanf("%d %d", &a, &b) != 2) {		printf("Entrada invalida.\n");		return 1;	}	printf("Menu de operaciones:\n");	printf("1) Suma\n");	printf("2) Resta\n");	printf("3) Multiplicacion\n");	printf("4) Division\n");	printf("Seleccione una opcion: ");	scanf("%d", &opcion);	switch (opcion) {	case 1:		printf("%d + %d = %d\n", a, b, a + b);		break;	case 2:		printf("%d - %d = %d\n", a, b, a - b);		break;	case 3:		printf("%d * %d = %d\n", a, b, a * b);		break;	case 4:		if (b == 0) {			printf("Error: division por cero.\n");		} else {			printf("%d / %d = %.2f\n", a, b, (double)a / b);		}		break;	default:		printf("Opcion invalida.\n");		break;	}	return 0;}
